changeSet.sql:
INSERT INTO notification_template ( id, name, subject, text) VALUES ( nextval('notification_template_seq'), 'NewVerificationBody', 'New maritime operator', 'You have been appointed as the verifier for ${emitterName} (${emitterId}).
You can manage the individual who is assigned as the site contact by navigating to [Manage verifier users]({"action": "VERIFICATION_BODY_USERS_SETUP"}).
You can assign and re-assign site contacts at any time.' );

INSERT INTO notification_template ( id, name, subject, text) VALUES ( nextval('notification_template_seq'), 'VerificationBodyNoLongerAvailable', 'Verifier is no longer available', 'The verifier you have appointed at your account has been removed or suspended by the regulator and is no longer available.
You can appoint a new verifier at any time from your dashboard by selecting "Manage users, contacts or verifiers" or by clicking on this link to [Manage users, contacts and verifiers]({"action": "ACCOUNT_USERS_SETUP", "accountId": ${accountId?c}}).
If you do not appoint a verifier now, you will be reminded at the end of each calendar year and prior to the deadline for submission of your Annual Emission Monitoring report that you must appoint a verifier.' );

INSERT INTO notification_template ( id, name, subject, text) VALUES ( nextval('notification_template_seq'), 'UserAccountCreated', 'User account created - Manage your UK ETS reporting', 'A UK ETS reporting service sign in has been created for ${userEmail}
You will be asked to provide this email address if you forget or want to change your password.
If you think this request should not have been made, you must [contact your regulator.](${contactRegulator}).
This is an automatic email - please do not reply to this address.' );

INSERT INTO notification_template ( id, name, subject, text) VALUES ( nextval('notification_template_seq'), 'ResetPasswordConfirmation', 'Password reset - Manage your UK ETS reporting', 'You have successfully reset your password for the UK ETS reporting service. You can now [sign in to your account](${homeUrl}).
If you did not request this reset you must [contact your regulator](${contactRegulator}).
This is an automatic email - please do not reply to this address.' );

